import type { ScaleLinear, ScaleSymLog } from 'd3-scale';

import type {
  ConvertibleUnit,
  FormatOptions,
  Unit,
} from '@dynatrace-sdk/units';

import { AnnotationsContainer } from './AnnotationsContainer.js';
import { useBehavioralTrackingProps } from '../../../../../../core/hooks/useBehavioralTrackingProps.js';
import { BehaviorTrackingProps } from '../../../../../../core/types/behavior-tracking-props.js';
import type { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import type { Formatter } from '../../../../types/formatter.js';
import { OverlayProvider } from '../../../overlay-tooltip/contexts/OverlayContext.js';
import { TooltipProvider } from '../../../overlay-tooltip/contexts/TooltipContext.js';
import { AnnotationsProviders } from '../../providers/AnnotationsProviders.js';
import type { AnnotationsTrackConfig } from '../../types/annotations-track-props.js';
import type { AnnotationsActionsHandler } from '../../types/annotations.js';
import type { TextOverflowOptions } from '../../types/marker.js';
import type { SelectionState } from '../../types/state.js';
import { AnnotationsRenderer } from '../AnnotationsRenderer.js';
import { AnnotationsOverlayTooltip } from '../tooltip/AnnotationsOverlayTooltip.js';
import { AnnotationsTooltipFormatterContext } from '../tooltip/contexts/AnnotationsTooltipFormatter.context.js';
import type { AnnotationsTooltipConfig } from '../tooltip/types/annotations-tooltip-props.js';

/**
 * @internal
 */
type AnnotationsNumericalDisplayProps = BehaviorTrackingProps & {
  tracks: AnnotationsTrackConfig[];
  scale: ScaleLinear<number, number> | ScaleSymLog<number, number>;
  showLabels: boolean;
  labelsOffset: number;
  width: number;
  textOverflow: TextOverflowOptions;
  truncateMode?: TruncationMode;
  maxLines?: number;
  formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
  annotationsActions?: AnnotationsActionsHandler;
  markerGroupHover?: (event: Partial<SelectionState>) => void;
  tooltipConfig?: AnnotationsTooltipConfig;
  /**
   * Optional data-dt-component attribute for RUM tracking.
   */
  'data-dt-component'?: string;
};

export const AnnotationsNumericalDisplay = (
  props: AnnotationsNumericalDisplayProps,
) => {
  const {
    annotationsActions,
    markerGroupHover,
    formatter,
    tooltipConfig,
    'data-dt-component': dataDtComponent,
    ...rendererProps
  } = props;

  const [behaviorTrackingProps] = useBehavioralTrackingProps(props);

  return (
    <OverlayProvider>
      <AnnotationsContainer
        {...behaviorTrackingProps}
        data-dt-component={dataDtComponent}
      >
        <TooltipProvider persistedStore>
          <AnnotationsProviders
            onAnnotationsMarkersInteraction={markerGroupHover}
            annotationsActions={annotationsActions}
            tooltipConfig={tooltipConfig}
          >
            <AnnotationsTooltipFormatterContext.Provider value={formatter}>
              <AnnotationsRenderer {...rendererProps} />
              <AnnotationsOverlayTooltip
                tooltipType="numerical"
                truncationMode={rendererProps.truncateMode}
                maxLines={rendererProps.maxLines}
              />
            </AnnotationsTooltipFormatterContext.Provider>
          </AnnotationsProviders>
        </TooltipProvider>
      </AnnotationsContainer>
    </OverlayProvider>
  );
};

AnnotationsNumericalDisplay['displayName'] = 'AnnotationsNumericalDisplay';
